use std::collections::HashMap;

#[derive(Debug)]
pub enum QueryResult {
    Success(String, Vec<u8>), // (Record Name, Raw Data)
    NotFound(String),
    Timeout(u64), // Milliseconds elapsed
    SecurityError(String, i32) // Error description and failure code
}

struct DnsCache {
    cache: HashMap<String, QueryResult>,
}

impl DnsCache {
    fn new() -> Self {
        DnsCache {
            cache: HashMap::new()
        }
    }

    fn insert_result(&mut self, name: &str, result: QueryResult) {
        self.cache.insert(String::from(name), result);
    }

    fn get_result(&self, name: &str) -> Option<&QueryResult> {
        self.cache.get(name)
    }
}

fn main() {
    let mut cache = DnsCache::new();

    let success_state = QueryResult::Success("google.com".to_string(), vec![0x63, 0x31]);
    cache.insert_result("google.com", success_state);

    let error_state = QueryResult::SecurityError("DNSSEC validation failed".to_string(), -1);
    cache.insert_result("badsite.net", error_state);

    match cache.get_result("google.com") {
        Some(result) => println!("Retrieved result: {:?}", result),
        None => println!("Result not found in cache.")
    }

    if let Some(QueryResult::SecurityError(_, code)) = cache.get_result("badsite.net") {
        println!("Successfully parsed error code: {}", *code);
    }
}

