use std::collections::{VecDeque, HashMap, HashSet};

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum RelationType {
    IsA,
    Uses,
    Connects,
}

#[derive(Debug, Clone)]
pub struct Node {
    pub id: u32,
    pub name: String,
    pub relations: HashMap<RelationType, Vec<u32>>
}

impl Node {
    pub fn new(id: u32, name: &str) -> Self {
        Node { 
            id, 
            name: name.to_string(), 
            relations: HashMap::new()
        }
    }

    pub fn add_relation(&mut self, relation_type: RelationType, target_id: u32) {
        self.relations.entry(relation_type).or_default().push(target_id);
    }
}

pub fn bfs_query(start_node_id: u32, graph: &HashMap<u32, Node>) -> Vec<u32> {
    let mut visited = HashSet::new();
    let mut queue = VecDeque::new();
    queue.push_back(start_node_id);
    visited.insert(start_node_id);
    let mut traversal_order = Vec::new();

    while let Some(current_id) = queue.pop_front() {
        traversal_order.push(current_id);
        if let Some(node) = graph.get(&current_id) {
            for (_, targets) in &node.relations {
                for &target_id in targets { 
                    if !visited.contains(&target_id) {
                        visited.insert(target_id);
                        queue.push_back(target_id);
                    }
                }
            }
        }
    }
    traversal_order
}

fn main() {
    let mut graph: HashMap<u32, Node> = HashMap::new();
    graph.insert(1, Node::new(1, "UserA"));
    graph.insert(2, Node::new(2, "ProductX"));
    graph.insert(3, Node::new(3, "CategoryY"));
    graph.insert(4, Node::new(4, "ServiceZ"));

    let mut user_a = graph.get_mut(&1).unwrap();
    user_a.add_relation(RelationType::Uses, 2);
    user_a.add_relation(RelationType::Connects, 3);
    drop(user_a);

    let mut product_x = graph.get_mut(&2).unwrap();
    product_x.add_relation(RelationType::IsA, 4);
    drop(product_x);

    graph.insert(1, Node { id: 1, name: "UserA".to_string(), relations: HashMap::from([(RelationType::Uses, vec![2]), (RelationType::Connects, vec![3])]) });
    graph.insert(2, Node { id: 2, name: "ProductX".to_string(), relations: HashMap::from([(RelationType::IsA, vec![4])]) });

    let bfs_path = bfs_query(1, &graph);
    println!("BFS Traversal Order: {:?}", bfs_path); 
}

use std::collections::HashMap;

struct Record {
    original_url: String,
    status: LinkStatus,
    metadata: HashMap<String, String>,
}

enum LinkStatus {
    Active(u64),
    Expired(u64),
    RedirectFailed(String),
}

impl LinkStatus {
    fn get_identifier(&self) -> u64 {
        match self {
            LinkStatus::Active(id) => *id,
            LinkStatus::Expired(id) => *id,
            LinkStatus::RedirectFailed(_) => 0,
        }
    }
}

fn process_record(record: Record) -> Result<String, String> {
    match record.status {
        LinkStatus::Active(expiry_time) if expiry_time > 0 => {
            Ok(format!("Success: Link is active and expires at {}", expiry_time))
        }
        LinkStatus::Expired(reason_code) => {
            Err(format!("Error: Link has already expired. Reason code: {}", reason_code))
        }
        LinkStatus::RedirectFailed(error_msg) => {
            Err(format!("Critical Error: Could not redirect. Details: {}", error_msg))
        }
        _ => todo!(),
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let active_record = Record {
        original_url: "https://example.com/test".to_string(),
        status: LinkStatus::Active(1678886400),
        metadata: HashMap::from([("owner".to_string(), "user123".to_string())]),
    };

    let expired_record = Record {
        original_url: "https://old.site/badlink".to_string(),
        status: LinkStatus::Expired(404),
        metadata: HashMap::new(),
    };

    println!("nProcessing Active Record:");
    match process_record(active_record) {
        Ok(msg) => println!("[DB Output]: {}", msg),
        Err(e) => println!("[DB Error]: {}", e),
    }

    println!("nProcessing Expired Record:");
    match process_record(expired_record) {
        Ok(msg) => println!("[DB Output]: {}", msg),
        Err(e) => println!("[DB Error]: {}", e),
    }

    Ok(())
}

use std::error::Error;
use std::fmt;

#[derive(Debug)]
pub enum ResourceData {
    Span { trace_id: String, operation_name: String, duration_ms: u64 },
    Metric { name: String, value: f64, timestamp: i64 },
    Summary { description: String, count: usize },
}

impl fmt::Display for ResourceData {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            ResourceData::Span { trace_id, operation_name, duration_ms } => {
                write!(f, "Span(trace={}, op='{}', dur={})", trace_id, operation_name, duration_ms)
            },
            ResourceData::Metric { name, value, timestamp } => {
                write!(f, "Metric(name='{}', val={}, ts={})", name, value, timestamp)
            },
            ResourceData::Summary { description, count } => {
                write!(f, "Summary(desc='{}', count={})", description, count)
            }
        }
    }
}

fn process_resource_data(data: ResourceData) -> Result<String, Box<dyn Error>> {
    match data {
        ResourceData::Span { trace_id, operation_name, duration_ms } => {
            println!("Found Span for tracing ID {}", trace_id);
            Ok(format!("Processed Span: {} units of work.", operation_name))
        }
        ResourceData::Metric { name, value, .. } => {
            println!("Collecting Metric data point for {}", name);
            Ok(format!("Aggregated Metric: {} at value {}.", name, value))
        }
        ResourceData::Summary { description, count } => {
            println!("Exporting Summary record: {}", description); 
            Ok(format!("Reported Summary: {} with {} entries.", description, count))
        }
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let data1 = ResourceData::Span { trace_id: "abc-123".to_string(), operation_name: "db_query".to_string(), duration_ms: 50 };
    println!("nProcessing Data 1: {}", data1);
    print!("Result 1: n{}", process_resource_data(data1)?);

    let data2 = ResourceData::Metric { name: "cpu_usage".to_string(), value: 0.85, timestamp: 1678886400 };
    println!("nProcessing Data 2: {}", data2);
    print!("Result 2: n{}", process_resource_data(data2)?);

    let data3 = ResourceData::Summary { description: "request_volume".to_string(), count: 42 };
    println!("nProcessing Data 3: {}", data3);
    print!("Result 3: n{}", process_resource_data(data3)?);

    Ok(())
}
